DROP TABLE IF EXISTS `ai_music_generations`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ai_music_generations` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '记录ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `prompt` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '生成提示词',
  `music_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '生成的音乐URL',
  `cover` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '封面图URL',
  `duration` int(11) DEFAULT '0' COMMENT '时长(秒)',
  `genre` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '音乐风格',
  `mood` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '情绪',
  `status` tinyint(4) DEFAULT '0' COMMENT '状态: 0处理中, 1成功, 2失败',
  `error_message` text COLLATE utf8mb4_unicode_ci COMMENT '错误信息',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_user` (`user_id`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='AI音乐生成表';
