DROP TABLE IF EXISTS `artists`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `artists` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '艺术家ID',
  `name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '艺术家名称',
  `avatar` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '头像URL',
  `cover` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '封面图URL',
  `description` text COLLATE utf8mb4_unicode_ci COMMENT '描述',
  `gender` tinyint(4) DEFAULT NULL COMMENT '性别: 0未知, 1男, 2女',
  `birthdate` date DEFAULT NULL COMMENT '生日',
  `region` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '地区',
  `fan_count` int(11) DEFAULT '0' COMMENT '粉丝数',
  `song_count` int(11) DEFAULT '0' COMMENT '歌曲数',
  `album_count` int(11) DEFAULT '0' COMMENT '专辑数',
  `status` tinyint(4) DEFAULT '1' COMMENT '状态: 0禁用, 1正常',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_name` (`name`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=152 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='艺术家表';
/*!40101 SET character_set_client = @saved_cs_client */;

