--
-- Table structure for table `song_hot_score`
--

DROP TABLE IF EXISTS `song_hot_score`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `song_hot_score` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `song_id` bigint(20) NOT NULL COMMENT '歌曲ID（唯一）',
  `play_score` int(11) DEFAULT '0' COMMENT '播放得分',
  `favorite_score` int(11) DEFAULT '0' COMMENT '收藏得分',
  `share_score` int(11) DEFAULT '0' COMMENT '分享得分',
  `download_score` int(11) DEFAULT '0' COMMENT '下载得分',
  `comment_score` int(11) DEFAULT '0' COMMENT '评论得分',
  `total_weighted_score` bigint(20) DEFAULT '0' COMMENT '加权总分',
  `hot_score` decimal(10,2) DEFAULT '0.00' COMMENT '热度得分(衰减后)',
  `rank` int(11) DEFAULT '0' COMMENT '当前排名',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `song_id` (`song_id`),
  KEY `idx_hot_score` (`hot_score`),
  KEY `idx_song` (`song_id`)
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='歌曲热度统计表';
/*!40101 SET character_set_client = @saved_cs_client */;

