  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_song` (`song_id`),
  KEY `idx_total` (`total_score`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='歌曲热度分数表';
