--
-- Table structure for table `songs`
--

DROP TABLE IF EXISTS `songs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `songs` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '歌曲ID',
  `title` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '歌曲标题',
  `duration` int(11) DEFAULT '0' COMMENT '时长(秒)',
  `url` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '歌曲URL',
  `lyrics` text COLLATE utf8mb4_unicode_ci COMMENT '歌词',
  `cover` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '封面图URL',
  `album_id` bigint(20) DEFAULT NULL COMMENT '专辑ID',
  `category_id` bigint(20) DEFAULT NULL COMMENT '分类ID',
  `play_count` bigint(20) DEFAULT '0' COMMENT '播放次数',
  `download_count` int(11) DEFAULT '0' COMMENT '下载次数',
  `status` tinyint(4) DEFAULT '1' COMMENT '状态: 0待审核, 1已发布, 2已下架',
  `is_original` tinyint(4) DEFAULT '0' COMMENT '是否原创: 0否, 1是',
  `user_id` bigint(20) DEFAULT NULL COMMENT '上传用户ID',
  `user_upload` tinyint(4) DEFAULT '0',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `share_count` int(11) DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `idx_title` (`title`),
  KEY `idx_album` (`album_id`),
  KEY `idx_category` (`category_id`),
  KEY `idx_status` (`status`),
  KEY `idx_play_count` (`play_count`),
  KEY `idx_user` (`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=569 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='歌曲表';
